import{_ as t,c as s,o as e,ai as n}from"./chunks/framework.TS84ywiI.js";const m=JSON.parse('{"title":"Spring Security 请求全过程解析","description":"","frontmatter":{},"headers":[],"relativePath":"SpringSecurity/SpringSecurity请求全过程解析.md","filePath":"SpringSecurity/SpringSecurity请求全过程解析.md"}'),r={name:"SpringSecurity/SpringSecurity请求全过程解析.md"};function a(o,i,g,p,l,h){return e(),s("div",null,i[0]||(i[0]=[n(`<h1 id="spring-security-请求全过程解析" tabindex="-1">Spring Security 请求全过程解析 <a class="header-anchor" href="#spring-security-请求全过程解析" aria-label="Permalink to &quot;Spring Security 请求全过程解析&quot;">​</a></h1><p>Spring Security 是一款基于 Spring 的安全框架，主要包含认证和授权两大安全模块，和另外一款流行的安全框架 Apache Shiro 相比，它拥有更为强大的功能。Spring Security 也可以轻松的自定义扩展以满足各种需求，并且对常见的 Web 安全攻击提供了防护支持。如果你的 Web 框架选择的是 Spring，那么在安全方面 Spring Security 会是一个不错的选择。</p><p>这里我们使用 Spring Boot 来集成 Spring Security，Spring Boot 版本为**<em>2.5.3</em><strong>，Spring Security 版本为</strong><em>5.5.1</em>**。</p><h2 id="开启-spring-security" tabindex="-1">开启 Spring Security <a class="header-anchor" href="#开启-spring-security" aria-label="Permalink to &quot;开启 Spring Security&quot;">​</a></h2><p>使用 IDEA 创建一个 Spring Boot 项目，然后引入**<em>spring-boot-starter-security</em>**：</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dependencies {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    implementation </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;org.springframework.boot:spring-boot-starter-security&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    implementation </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;org.springframework.boot:spring-boot-starter-web&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    implementation </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;org.projectlombok:lombok:1.18.8&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    annotationProcessor </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;org.projectlombok:lombok:1.18.8&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    providedRuntime </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;org.springframework.boot:spring-boot-starter-tomcat&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    testImplementation </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;org.springframework.boot:spring-boot-starter-test&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    testImplementation </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;org.springframework.security:spring-security-test&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>接下来我们创建一个**<em>HelloController</em>**，对外提供一个<strong><i>/hello</i></strong>服务：</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RestController</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> HelloController</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GetMapping</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    public</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> String </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hello</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello world&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>这时候我们直接启动项目，访问<strong><i><a href="http://localhost:8080/hello" target="_blank" rel="noreferrer">http://localhost:8080/hello</a></i></strong>，可以看到页面跳转到一个登陆页面：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811091508157.png" alt="image-20210811091508157"></p><p>默认的用户名为 user，密码由 Sping Security 自动生成，回到 IDEA 的控制台，可以找到密码信息：</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Using generated security password</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 4f06ba04</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">37e9</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">4bdd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">a085</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">3305260da0d6</span></span></code></pre></div><p>输入用户名 user，密码 4f06ba04-37e9-4bdd-a085-3305260da0d6 后，我们便可以成功访问<strong><i>/hello</i></strong>接口。</p><h2 id="基本原理" tabindex="-1">基本原理 <a class="header-anchor" href="#基本原理" aria-label="Permalink to &quot;基本原理&quot;">​</a></h2><p>Spring Security 默认为我们开启了一个简单的安全配置，下面让我们来了解其原理。</p><p>当 Spring Boot 项目配置了 Spring Security 后，Spring Security 的整个加载过程如下图所示：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811091633434.png" alt="image-20210811091633434"></p><p>而当我们访问<strong><i><a href="http://localhost:8080/hello" target="_blank" rel="noreferrer">http://localhost:8080/hello</a></i></strong>时，代码的整个执行过程如下图所示：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811091659121.png" alt="image-20210811091659121"></p><p>如上图所示，Spring Security 包含了众多的过滤器，这些过滤器形成了一条链，所有请求都必须通过这些过滤器后才能成功访问到资源。</p><p>下面我们通过 debug 来验证这个过程：</p><p>首先，通过前面可以知道，当有请求来到时，最先由**<em>DelegatingFilterProxy</em><strong>负责接收，因此在</strong><em>DelegatingFilterProxy</em>**的<strong><i>doFilter()</i></strong>的首行打上断点：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811091719470.png" alt="image-20210811091719470"></p><p>接着**<em>DelegatingFilterProxy</em><strong>会将请求委派给</strong><em>FilterChainProxy</em><strong>进行处理，在</strong><em>FilterChainProxy</em>**的首行打上断点：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/56ac5128-eab7-4b92-912f-ff50bac68a4f.png" alt="img"></p><p>**<em>FilterChainProxy</em><strong>会在<strong><i>doFilterInternal()</i></strong>中生成一个内部类</strong><em>VirtualFilterChain</em><strong>的实例，以此来调用 Spring Security 的整条过滤器链，在</strong><em>VirtualFilterChain</em>**的<strong><i>doFilter()</i></strong>首行打上断点：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811091755498.png" alt="image-20210811091755498"></p><p>接下来**<em>VirtualFilterChain</em><strong>会通过</strong><em>currentPosition</em><strong>依次调用存在</strong><em>additionalFilters</em><strong>中的过滤器，其中比较重要的几个过滤器有：</strong><em>UsernamePasswordAuthenticationFilter</em><strong>、</strong><em>DefaultLoginPageGeneratingFilter</em><strong>、</strong><em>AnonymousAuthenticationFilter</em><strong>、</strong><em>ExceptionTranslationFilter</em><strong>、</strong><em>FilterSecurityInterceptor</em>**，我们依次在这些过滤器的<strong><i>doFilter()</i></strong>的首行打上断点：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811091815473.png" alt="image-20210811091815473"></p><p>准备完毕后，我们启动项目，然后访问<strong><i><a href="http://localhost:8080/hello" target="_blank" rel="noreferrer">http://localhost:8080/hello</a></i></strong>，程序首先跳转到**<em>DelegatingFilterProxy</em>**的断点上：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811091833065.png" alt="image-20210811091833065"></p><p>此时**<em>delegate</em><strong>还是 null 的，接下来依次执行代码，可以看到</strong><em>delegate</em><strong>最终被赋值一个</strong><em>FilterChainProxy</em>**的实例：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/f045b025-bd97-4222-8a02-51634be6745b.png" alt="img"></p><p>接下来程序依次跳转到**<em>FilterChainProxy</em><strong>的<strong><i>doFilter()</i></strong>和</strong><em>VirtualFilterChain</em>**的<strong><i>doFilter()</i></strong>中：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/90d3e369-510f-45cb-982d-241d2eedb55c.png" alt="img"></p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/image-20210811092048784.png" alt="image-20210811092048784"></p><p>接着程序跳转到**<em>AbstractAuthenticationProcessingFilter</em><strong>（</strong><em>UsernamePasswordAuthenticationFilter</em>**的父类）的<strong><i>doFilter()</i></strong>中，通过<strong><i>requiresAuthentication()</i></strong>判定为 false（是否是 POST 请求）：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/2e5440bc-9488-4213-a030-0d25153bb2ea.png" alt="img"></p><p>接着程序跳转到**<em>DefaultLoginPageGeneratingFilter</em>**的<strong><i>doFilter()</i></strong>中，通过<strong><i>isLoginUrlRequest()</i></strong>判定为 false（请求路径是否是<strong><i>/login</i></strong>）：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/47a7bca4-d858-4cb1-b126-347805b74053.png" alt="img"></p><p>接着程序跳转到**<em>AnonymousAuthenticationFilter</em><strong>的<strong><i>doFilter()</i></strong>中，由于是首次请求，此时<strong><i>SecurityContextHolder.getContext().getAuthentication()</i></strong>为 null，因此会生成一个</strong><em>AnonymousAuthenticationToken</em>**的实例：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/6b1aded6-5229-47ba-b192-78a7c2622b8c.png" alt="img"></p><p>接着程序跳转到**<em>ExceptionTranslationFilter</em><strong>的<strong><i>doFilter()</i></strong>中，</strong><em>ExceptionTranslationFilter</em><strong>负责处理</strong><em>FilterSecurityInterceptor</em>**抛出的异常，我们在 catch 代码块的首行打上断点：</p><p><strong><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/8efa0b1c-2b32-4d5b-9655-985374326e10.png" alt="img"></strong></p><p>接着程序跳转到**<em>FilterSecurityInterceptor</em><strong>的<strong><i>doFilter()</i></strong>中，依次执行代码后程序停留在其父类(</strong><em>AbstractSecurityInterceptor</em>**)的<strong><i>attemptAuthorization()</i></strong>中：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/d6e99143-6207-43a5-8d04-f0c81baa11b4.png" alt="img"></p><p><strong><em>accessDecisionManager</em><strong>是</strong><em>AccessDecisionManager</em></strong>(访问决策器)的实例，<strong><em>AccessDecisionManager</em><strong>主要有 3 个实现类：</strong><em>AffirmativeBased</em></strong>(一票通过)，<strong>ConsensusBased</strong>(少数服从多数)、UnanimousBased(一票否决)，此时**<em>AccessDecisionManager</em><strong>的的实现类是</strong><em>AffirmativeBased</em><strong>，我们可以看到程序进入</strong><em>AffirmativeBased</em>**的<strong><i>decide()</i></strong>中：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/6724647c-34ee-4a57-8cfa-b46f57400d14.png" alt="img"></p><p>从上图可以看出，决策的关键在<strong><i>voter.vote(authentication, object, configAttributes)</i></strong>这句代码上，通过跟踪调试，程序最终进入**<em>AuthenticationTrustResolverImpl</em>**的<strong><i>isAnonymous()</i></strong>中：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/4beaa02f-a93d-4d95-9ad1-0d7213cb0e46.png" alt="img"></p><p><strong><i>isAssignableFrom()</i></strong>判断前者是否是后者的父类，而**<em>anonymousClass</em><strong>被固定为</strong><em>AnonymousAuthenticationToken.class</em><strong>，参数</strong><em>authentication</em><strong>由前面</strong><em>AnonymousAuthenticationFilter</em><strong>可以知道是</strong><em>AnonymousAuthenticationToken</em><strong>的实例，因此<strong><i>isAnonymous()</i></strong>返回 true，</strong><em>FilterSecurityInterceptor</em><strong>抛出</strong><em>AccessDeniedException</em><strong>异常，程序返回</strong><em>ExceptionTranslationFilter</em>**的 catch 块中：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/8e1ac9db-5987-484d-abf4-4c6535c60cc6.png" alt="img"></p><p>接着程序会依次进入**<em>DelegatingAuthenticationEntryPoint</em><strong>、</strong><em>LoginUrlAuthenticationEntryPoint</em><strong>中，最后由</strong><em>LoginUrlAuthenticationEntryPoint</em>**的<strong><i>commence()</i></strong>决定重定向到<strong><i>/login</i></strong>：</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/SpringSecurity/1b03bdd4-6773-4b39-a664-fdf65d104403.png" alt="img"></p><p>后续对<strong><i>/login</i></strong>的请求同样会经过之前的执行流程，在**<em>DefaultLoginPageGeneratingFilter</em><strong>的<strong><i>doFilter()</i></strong>中，通过<strong><i>isLoginUrlRequest()</i></strong>判定为 true（请求路径是否是<strong><i>/login</i></strong>）,直接返回</strong><em>login.html</em>**，也就是我们开头看到的登录页面。</p><p>当我们输入用户名和密码，点击**<em>Sign in</em><strong>，程序来到</strong><em>AbstractAuthenticationProcessingFilter</em><strong>的<strong><i>doFilter()</i></strong>中，通过<strong><i>requiresAuthentication()</i></strong>判定为 true（是否是 POST 请求）,因此交给其子类</strong><em>UsernamePasswordAuthenticationFilter</em><strong>进行处理，</strong><em>UsernamePasswordAuthenticationFilter</em><strong>会将用户名和密码封装成一个</strong><em>UsernamePasswordAuthenticationToken</em>**的实例并进行校验，当校验通过后会将请求重定向到我们一开始请求的路径：<strong><i>/hello</i></strong>。</p><p>后续对<strong><i>/hello</i></strong>的请求经过过滤器链时就可以一路开绿灯直到最终交由**<em>HelloController</em>**返回&quot;Hello World&quot;。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ol><li><p><a href="https://docs.spring.io/spring-security/site/docs/current/reference/html5/" target="_blank" rel="noreferrer">Spring Security Reference</a></p></li><li><p><a href="https://mrbird.cc/Spring-Boot&amp;Spring-Security.html" target="_blank" rel="noreferrer">Spring Boot 中开启 Spring Security</a></p></li></ol>`,59)]))}const d=t(r,[["render",a]]);export{m as __pageData,d as default};
